export interface Place {
  name: string;
  slug: string;
  desc: string;
  category: string;
  highlights: string[];
  bestTime: string;
  duration: string;
  emoji: string;
  img?: string;
}

export interface StateData {
  name: string;
  slug: string;
  coverImg: string;
  tagline: string;
  tagColor: string;
  icon: string;
  accentColor: string;
  heroDesc: string;
  places: Place[];
}

function slugify(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

export function slugifyPlace(name: string): string {
  return slugify(name);
}

export const KARNATAKA: StateData = {
  name: 'Karnataka', slug: 'karnataka', coverImg: '/states/karnataka-cover.jpg',
  tagline: 'Heritage & Nature', tagColor: 'text-amber-400', icon: '🏛️', accentColor: 'amber',
  heroDesc: 'From the royal palaces of Mysuru to the ancient ruins of Hampi, from the coffee hills of Coorg to the tech capital Bengaluru, from the pristine beaches of Gokarna to the wild jungles of Bandipur — explore every corner of Karnataka with RRM Holidays.',
  places: [
    { name: 'Bengaluru', slug: 'bengaluru', desc: 'India\'s Silicon Valley and IT capital with vibrant nightlife, beautiful parks like Lalbagh and Cubbon, world-class restaurants, shopping malls, tech parks, and a perfect blend of modern urban life with traditional South Indian culture. Known as the Garden City for its lush greenery and pleasant weather year-round, Bengaluru offers everything from heritage sites like Bangalore Palace to trendy microbreweries and a thriving startup ecosystem.', category: 'Capital City', highlights: ['Lalbagh Botanical Garden', 'Cubbon Park', 'Bangalore Palace', 'MG Road', 'Vidhana Soudha', 'UB City Mall'], bestTime: 'Sep - Feb', duration: '2-3 Days', emoji: '🏙️', img: '/bengaluru-city.jpg' },
    { name: 'Mysore', slug: 'mysore', desc: 'The City of Palaces, famous for the magnificent Mysore Palace illuminated by 97,000 bulbs during Dasara, the sacred Chamundi Hills with its ancient Chamundeshwari Temple, the musical Brindavan Gardens, sandalwood products, Mysore silk sarees, and the grand Dasara festival that attracts millions of visitors every year. The city exudes old-world charm with its heritage buildings, yoga centers, and delectable Mysore Pak.', category: 'Heritage City', highlights: ['Mysore Palace', 'Chamundi Hills', 'Brindavan Gardens', 'KRS Dam', 'St. Philomena\'s Church', 'Mysore Zoo'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🏛️', img: '/mysore-temple.jpg' },
    { name: 'Mangalore', slug: 'mangalore', desc: 'Coastal gem of Karnataka with stunning beaches, ancient temples like Kadri Manjunath, delicious seafood cuisine, and the gateway to the Western Ghats. Known for its cashew processing industry and Udupi-style vegetarian food that has gained worldwide fame. The city offers a unique blend of coastal beauty, spiritual heritage, and culinary excellence.', category: 'Coastal City', highlights: ['Panambur Beach', 'Someshwara Temple', 'Kadri Temple', 'Tannirbhavi Beach', 'Sultan Battery', 'Pilikula Nisargadhama'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🏖️', img: '/mangalore-beach.jpg' },
    { name: 'Hampi', slug: 'hampi', desc: 'UNESCO World Heritage Site with breathtaking ruins of the Vijayanagara Empire spread across 26 square kilometers. The surreal boulder-strewn landscape, ancient temples like Virupaksha, the iconic Stone Chariot, the Queen\'s Bath, and the massive boulder formations create one of India\'s most photographed archaeological sites. A paradise for history lovers, photographers, and backpackers from around the world.', category: 'Heritage', highlights: ['Virupaksha Temple', 'Stone Chariot', 'Hemakuta Hill', 'Tungabhadra River', 'Queen\'s Bath', 'Vittala Temple'], bestTime: 'Oct - Feb', duration: '2-3 Days', emoji: '🏛️', img: '/hampi.jpg' },
    { name: 'Coorg (Kodagu)', slug: 'coorg', desc: 'The Scotland of India — lush coffee plantations stretching across misty hills, cascading waterfalls like Abbey Falls, rich Kodava culture with unique traditions and cuisine, and dense forests teeming with wildlife. Perfect for nature lovers, trekkers, and anyone seeking a peaceful mountain retreat. The aroma of freshly brewed coffee, the sight of mist-covered hills, and the warmth of Kodava hospitality make Coorg unforgettable.', category: 'Hill Station', highlights: ['Abbey Falls', 'Raja\'s Seat', 'Dubare Elephant Camp', 'Coffee Plantations', 'Iruppu Falls', 'Namdroling Monastery'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🏔️', img: '/coorg.jpg' },
    { name: 'Chikmagalur', slug: 'chikmagalur', desc: 'Coffee capital of Karnataka nestled in the Western Ghats. Home to Mullayanagiri — the highest peak in Karnataka at 1,930 meters — and famous for its aromatic coffee estates, serene homestays, breathtaking mountain trails, and beautiful waterfalls like Hebbe and Jhari. The town offers a perfect escape from city life with its cool climate, misty mornings, and endless green landscapes.', category: 'Hill Station', highlights: ['Mullayanagiri Peak', 'Baba Budangiri', 'Hebbe Falls', 'Coffee Estates', 'Kudremukh Trek', 'Bhadra Wildlife Sanctuary'], bestTime: 'Sep - Mar', duration: '2-3 Days', emoji: '🏔️', img: '/chikmagalur-hills.jpg' },
    { name: 'Hassan', slug: 'hassan', desc: 'Gateway to Karnataka\'s architectural treasures including the stunning Hoysala temples of Belur and Halebidu — masterpieces of intricate stone carving from the 12th century. The colossal monolithic Gomateshwara statue at Shravanabelagola, standing 57 feet tall atop Vindhyagiri Hill, is one of the world\'s tallest free-standing monolithic statues and an important Jain pilgrimage center.', category: 'Heritage', highlights: ['Belur Temple', 'Halebidu Temple', 'Shravanabelagola', 'Gomateshwara Statue', 'Gorur Dam', 'Chennakeshava Temple'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏛️', img: '/hassan-temple.jpg' },
    { name: 'Hubli–Dharwad', slug: 'hubli-dharwad', desc: 'Twin cities forming a major commercial and educational hub of North Karnataka. Known for their prestigious educational institutions, bustling wholesale markets, beautiful temples like the ancient Chandramouleshwara, serene Unkal Lake, and as a strategic gateway to historic sites like the Bijapur monuments and the beaches of Goa.', category: 'Commercial Hub', highlights: ['Chandramouleshwara Temple', 'Unkal Lake', 'Indira Glass House', 'Nrupatunga Hill', 'Siddharoodha Math', 'Bannerughatta'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏙️', img: '/states/karnataka-cover.jpg' },
    { name: 'Belgaum', slug: 'belgaum', desc: 'Border city with a rich cultural heritage straddling Karnataka and Maharashtra. Known for its pleasant weather year-round, the ancient Belgaum Fort with its impressive bastions, beautiful Jain temples like Kamal Basti, the stunning Godchinamalaki Falls, and a unique melting pot of Maharashtrian and Kannada cultures with delicious culinary traditions blending both cuisines.', category: 'Border City', highlights: ['Belgaum Fort', 'Kamal Basti', 'Gokak Falls', 'Godchinamalaki Falls', 'Jamboti Hills', 'Military Mahadeva Temple'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏙️', img: '/belgaum-fort.jpg' },
    { name: 'Gulbarga (Kalaburagi)', slug: 'gulbarga', desc: 'Historic city with impressive Islamic architecture from the Bahmani Sultanate era. The massive Gulbarga Fort is one of the largest forts in South India, while the Jama Masjid inside is modeled on the great mosque of Cordoba in Spain. The city is also home to the revered Sharana Basaveshwara Temple and the tomb of Khwaja Bande Nawaz, attracting both history enthusiasts and spiritual seekers.', category: 'Historic City', highlights: ['Gulbarga Fort', 'Jama Masjid', 'Sharana Basaveshwara Temple', 'Khwaja Bande Nawaz', 'Shri Sharanabasaveshwara Temple', 'Chor Gumbad'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/states/karnataka-cover.jpg' },
    { name: 'Bellary', slug: 'bellary', desc: 'Mining and industrial hub surrounded by historic forts and natural beauty. The Bellary Fort, built by Hanumappa Nayaka on top of the Ballari Gudda hill, offers panoramic views of the city. The city serves as a gateway to Hampi, one of India\'s greatest UNESCO World Heritage Sites, and the scenic Tungabhadra Dam area.', category: 'Industrial City', highlights: ['Bellary Fort', 'Kumaraswamy Temple', 'Hampi Gateway', 'Tungabhadra Dam', 'Daroji Bear Sanctuary', 'Kuntegadda Park'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏙️', img: '/hampi.jpg' },
    { name: 'Hospet', slug: 'hospet', desc: 'The main gateway to Hampi and the Tungabhadra Dam area. This bustling town serves as the primary base for the millions of tourists visiting the UNESCO World Heritage Site of Hampi every year. The Tungabhadra Dam offers beautiful gardens and boat rides, while the nearby Sanapur Lake and Anegundi village provide additional exploration opportunities.', category: 'Gateway to Hampi', highlights: ['Tungabhadra Dam', 'Hampi Access Point', 'Sanapur Lake', 'Anegundi Village', 'Chitradurga Gateway', 'Garden Park'], bestTime: 'Oct - Feb', duration: '2-3 Days', emoji: '🗺️', img: '/hampi.jpg' },
    { name: 'Gadag', slug: 'gadag', desc: 'Rich in architectural heritage with stunning temples from the Chalukya and Hoysala periods. The Trikuteshwara Temple complex with its three Shiva lingas is a masterpiece of Western Chalukya architecture. The town is also the birthplace of the legendary Kannada poet Kumaravyasa, who wrote the Mahabharata in Kannada, and the nearby Lakkundi site has over 100 ancient temples.', category: 'Temple Town', highlights: ['Trikuteshwara Temple', 'Veera Narayana Temple', 'Lakkundi Heritage Site', 'Dambal', 'Sudi Temple Complex', 'Magadi Bird Sanctuary'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🛕', img: '/hassan-temple.jpg' },
    { name: 'Davangere', slug: 'davangere', desc: 'Famous across India for its signature Davangere Benne Dosa — a crispy butter dosa that food lovers travel miles to taste. This city is a major agricultural and educational hub of Central Karnataka, surrounded by scenic Channagiri hills, beautiful lakes like Kunduvada Kere and Sulekere (one of the largest lakes in Karnataka), and a growing industrial sector.', category: 'Culinary City', highlights: ['Benne Dosa', 'Channagiri Hills', 'Kunduvada Kere Lake', 'Sulekere Lake', 'Shivamogga Gateway', 'Durgambika Temple'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🍽️', img: '/states/karnataka-cover.jpg' },
    { name: 'Chitradurga', slug: 'chitradurga', desc: 'Known as the "Stone Fortress City" with the massive Chitradurga Fort spanning seven hills, built over centuries by various dynasties. Legend has it that the brave Onake Obavva single-handedly fought invaders through a crevice in the fort walls. The mysterious Chandravalli Caves, Hidimbeshwara Temple, and Ankali Mutt add to this city\'s legendary status from the Mahabharata period.', category: 'Fort City', highlights: ['Chitradurga Fort', 'Chandravalli Caves', 'Hidimbeshwara Temple', 'Ankali Mutt', 'Obavvana Kindi', 'Jogimatti Hills'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏰', img: '/chitradurga-fort.jpg' },
    { name: 'Shimoga (Shivamogga)', slug: 'shimoga', desc: 'Called the "Gateway of Malnad" with stunning Jog Falls — India\'s second highest waterfall at 253 meters — created by the Sharavathi River plunging down in four distinct cascades. Surrounded by lush green forests, the serene Western Ghats, Lion Safari at Tyavarekoppa, the biodiversity hotspot of Agumbe rainforest (one of the wettest places in India), and beautiful nature camps make this a paradise for nature enthusiasts.', category: 'Nature Hub', highlights: ['Jog Falls', 'Koodigudde Nature Camp', 'Lion Safari Tyavarekoppa', 'Agumbe Rainforest', 'Kundadri Hills', 'Sharavathi Valley'], bestTime: 'Jul - Jan', duration: '2-3 Days', emoji: '🌿', img: '/jog-falls.jpg' },
    { name: 'Udupi', slug: 'udupi', desc: 'Famous for the ancient Udupi Sri Krishna Temple established by the 13th-century saint Madhwacharya, and its legendary vegetarian cuisine — the Udupi restaurant chain serves millions daily across India. The coastal town boasts pristine beaches like Malpe, the unique hexagonal basalt rock formations at St. Mary\'s Island (accessible only by boat), and the prestigious Manipal University nearby.', category: 'Temple Town', highlights: ['Sri Krishna Temple', 'Malpe Beach', 'St. Mary\'s Island', 'Manipal University', 'Kaup Beach Lighthouse', 'Anantheshwara Temple'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🛕', img: '/udupi-beach.jpg' },
    { name: 'Kolar', slug: 'kolar', desc: 'Historic city known for the magnificent Kotilingeshwara Temple with over one million Shiva lingas — one of the largest collections in the world. The golden mines of Kolar Gold Fields (KGF), once among the deepest gold mines in the world, have a fascinating colonial-era legacy. The cave temple of Antaragange, with its natural spring emerging from underground caves, and the ancient Kolaramma Temple add to Kolar\'s spiritual significance.', category: 'Historic City', highlights: ['Kotilingeshwara Temple', 'Kolar Gold Fields', 'Antaragange', 'Kolaramma Temple', 'Someshwara Temple', 'Bangarpet'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/kolar-temple.jpg' },
    { name: 'Mandya', slug: 'mandya', desc: 'Known as the "Sugar Bowl of Karnataka" with vast sugarcane fields stretching to the horizon. The crown jewel is the Krishna Raja Sagara (KRS) Dam across the Kaveri River and the magnificent Brindavan Gardens with its musical fountain — one of the most visited gardens in India. The nearby Ranganthittu Bird Sanctuary (home to thousands of migratory birds) and the spectacular Shivanasamudra Falls make Mandya a must-visit destination.', category: 'Agricultural Hub', highlights: ['KRS Dam', 'Brindavan Gardens', 'Ranganthittu Bird Sanctuary', 'Shivanasamudra Falls', 'Cauvery River', 'Melukote Temple'], bestTime: 'Jul - Jan', duration: '1-2 Days', emoji: '🌾', img: '/mysore-temple.jpg' },
    { name: 'Tumakuru (Tumkur)', slug: 'tumakuru', desc: 'A rapidly growing industrial and educational city known for the beautiful Devarayana Durga hills with ancient hilltop temples, the revered Siddaganga Mutt (an important educational institution), the mysterious Namada Chilume (a natural spring believed to be created by Lord Rama), and the adventurous Makalidurga night trek. The city serves as a gateway to the scenic Western Ghats mountain ranges.', category: 'Industrial City', highlights: ['Devarayana Durga', 'Siddaganga Mutt', 'Namada Chilume', 'Makalidurga Trek', 'Kunigal Stud Farm', 'Goravanahalli Lakshmi Temple'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏙️', img: '/chikmagalur-hills.jpg' },
    { name: 'Bidar', slug: 'bidar', desc: 'Ancient city with the magnificent Bidar Fort — one of the most formidable medieval forts in India, featuring Islamic architecture, royal palaces, and mosques within its massive walls. The city is renowned worldwide for its unique Bidriware metal handicrafts — intricate silver inlay work on blackened zinc. The beautiful Bahmani and Baridi tombs, Guru Nanak Jhira (a sacred Sikh shrine with natural spring water), and the Narasimha Jhira Cave temple make Bidar a heritage treasure.', category: 'Historic City', highlights: ['Bidar Fort', 'Guru Nanak Jhira', 'Bahmani Tombs', 'Narasimha Jhira Cave', 'Bidriware Handicrafts', 'Chaubara Clock Tower'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/bidar-fort.jpg' },
    { name: 'Bijapur (Vijayapura)', slug: 'bijapur', desc: 'Treasure house of Islamic architecture with the iconic Gol Gumbaz — the second largest dome in the world (after St. Peter\'s Basilica) with its famous Whispering Gallery where even a whisper can be heard across 38 meters. The stunning Ibrahim Rauza (often called the Taj Mahal of the South), the massive Malik-e-Maidan cannon (one of the largest medieval cannons), and numerous beautiful mosques from the Adil Shahi dynasty make Bijapur an architectural paradise.', category: 'Heritage City', highlights: ['Gol Gumbaz', 'Ibrahim Rauza', 'Jama Masjid', 'Malik-e-Maidan Cannon', 'Bara Kaman', 'Upri Buruj'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/gol-gumbaz.jpg' },
    { name: 'Raichur', slug: 'raichur', desc: 'Ancient city on the banks of the Tungabhadra River with a massive hilltop fort that has witnessed the rise and fall of empires — from the Chalukyas to the Vijayanagara kings and the Nizams of Hyderabad. The Ek Minar Ki Masjid, the grand Jama Masjid, and the ancient Markandeshwara Temple reflect the city\'s rich multi-religious heritage. An important gateway between Karnataka and Andhra Pradesh.', category: 'Historic City', highlights: ['Raichur Fort', 'Ek Minar Ki Masjid', 'Jama Masjid', 'Markandeshwara Temple', 'Hammira Fort', 'Navanagar'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🏛️', img: '/states/karnataka-cover.jpg' },
    { name: 'Adoni', slug: 'adoni', desc: 'Historic city known for the massive Adoni Fort perched on a granite hill, one of the largest forts in the Deccan plateau with a network of underground passages. The ancient Rajoleswara Temple, the historic Jumma Masjid, and the sacred Ramatalai Temple reflect the city\'s rich heritage. Adoni was once a prosperous trading center under the Vijayanagara Empire and showcases a charming blend of Telugu and Kannada cultures.', category: 'Fort City', highlights: ['Adoni Fort', 'Rajoleswara Temple', 'Jumma Masjid', 'Ramatalai Temple', 'Underground Passages', 'Dargah Hazrat Shah'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🏰', img: '/states/karnataka-cover.jpg' },
    { name: 'Guntakal', slug: 'guntakal', desc: 'Major railway junction of South India connecting Karnataka, Andhra Pradesh, and other regions. An important transit hub for travelers exploring the Deccan plateau and the Rayalaseema region. The nearby Mukundra Hills offer scenic beauty and spiritual sites, while the British-era railway architecture and the ancient Karna Temple add to the town\'s unique character as a gateway to both states.', category: 'Railway Hub', highlights: ['Railway Junction', 'Mukundra Hills', 'Karna Temple', 'British-era Architecture', 'Tungabhadra Access', 'Bellary Gateway'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🚂', img: '/states/karnataka-cover.jpg' },
    { name: 'Bhadravati', slug: 'bhadravati', desc: 'Industrial town on the banks of the Bhadra River, home to the historic Visvesvaraya Iron and Steel Plant established in 1923 by Sir M. Visvesvaraya. The town is surrounded by lush green forests and is close to the wildlife-rich Bhadra Tiger Reserve — one of the best places in Karnataka to spot tigers, elephants, and diverse wildlife in their natural habitat. The Lakshmi Narasimha Temple adds spiritual charm.', category: 'Industrial City', highlights: ['Bhadra Dam', 'Bhadra Wildlife Sanctuary', 'Vishweshwaraiah Museum', 'Lakshmi Narasimha Temple', 'IGL Steel Plant', 'Bhadra River'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏙️', img: '/chikmagalur-hills.jpg' },
    { name: 'Badami', slug: 'badami', desc: 'Ancient capital of the Chalukya dynasty, renowned for its stunning rock-cut cave temples dating back to the 6th century. Nestled in a picturesque ravine between two sandstone hills, the four cave temples feature exquisite sculptures of Hindu deities, including an 18-armed Nataraja striking 81 dance poses in the first cave. The Agastya Theertha lake below the caves, the Bhoothanatha temples at the edge of the serene waters, and the rich red sandstone cliffs create a landscape of extraordinary beauty. Badami along with Aihole and Pattadakal forms the golden triangle of Chalukya architecture.', category: 'Heritage', highlights: ['Cave Temples', 'Bhoothanatha Temple', 'Agastya Theertha Lake', '18-Armed Nataraja', 'Chalukya Architecture', 'Red Sandstone Cliffs'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/badami-caves.jpg' },
    { name: 'Pattadakal', slug: 'pattadakal', desc: 'UNESCO World Heritage Site and the coronation capital of the Chalukya kings, standing as a testament to the richness of Chalukyan architecture on the banks of the Malaprabha River. The temple complex showcases a remarkable blend of northern Nagara and southern Dravida architectural styles — the only place in India where both styles are displayed side by side. The 8th-century temples of Jambulinga, Kadasiddeshvara, and Galaganatha with their curvilinear shikaras are masterpieces. The ornate Papanatha Temple features delicately chiselled ceilings and a 16-pillared main hall, making Pattadakal a living museum of Indian temple architecture spanning centuries of artistic evolution.', category: 'Heritage', highlights: ['UNESCO World Heritage', 'Virupaksha Temple', 'Papanatha Temple', 'Nagara-Dravida Blend', 'Malaprabha River', 'Galaganatha Temple'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🏛️', img: '/pattadakal.jpg' },
    { name: 'Aihole', slug: 'aihole', desc: 'Acclaimed as the cradle of Hindu temple architecture, Aihole is an idyllic village on the banks of the Malaprabha River with over 100 ancient temples scattered across its landscape. Among these, the most impressive is the Durga Temple with its semicircular apse, elevated plinth, and a gallery encircling the sanctum — a revolutionary design that influenced centuries of Indian temple building. The Lad Khan Temple, Huchimalli Gudi, and Ravanaphadi cave demonstrate the evolutionary journey of Chalukya architecture from simple rock-cut shrines to elaborate structural temples. Walking through Aihole is like walking through an open-air museum spanning centuries of Indian artistry.', category: 'Heritage', highlights: ['Durga Temple', 'Lad Khan Temple', 'Ravanaphadi Cave', '100+ Ancient Temples', 'Chalukya Architecture', 'Malaprabha River'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🏛️', img: '/aihole.jpg' },
    { name: 'Srirangapatna', slug: 'srirangapatna', desc: 'Island fortress of the legendary warrior king Tipu Sultan, situated on the Kaveri River just 20 km from Mysuru. This historic town is where Tipu Sultan made his last stand against the British in 1799, and his legacy lives on in the magnificent Srirangapatna Fort, the Gumbaz (his mausoleum with ivory-inlaid doors), the Daria Daulat Bagh (his summer palace with beautiful frescoes depicting his battles), and the dungeons where British officers were once imprisoned. The sacred Ranganatha Swamy Temple, one of the largest Vishnu temples in Karnataka, the Wellesley Bridge built by the British, and the colonnaded colonnade of ancient bazaars add to the town\'s rich historical tapestry spanning Hindu, Muslim, and colonial heritage.', category: 'Heritage', highlights: ['Tipu Sultan Fort', 'Gumbaz Mausoleum', 'Daria Daulat Bagh', 'Ranganatha Swamy Temple', 'Wellesley Bridge', 'Summer Palace'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🏰', img: '/srirangapatna.jpg' },
    { name: 'Bandipur National Park', slug: 'bandipur', desc: 'One of India\'s finest wildlife reserves and a UNESCO Biosphere Reserve, spanning 874 square kilometers at the confluence of the Western Ghats and the Deccan Plateau. Once the private hunting ground of the Mysuru Maharaja, Bandipur is now home to over 100 tigers, thousands of Asian elephants, gaurs, sloth bears, leopards, and over 200 species of birds. The park is part of the Nilgiri Biosphere Reserve — India\'s largest biosphere reserve — and offers thrilling jungle safaris through dense forests, open grasslands, and along the Kabini River where elephants gather in large herds during summer. The picturesque backdrop of the enchanting Nilgiri hills and mist-covered peaks makes every safari a magical experience.', category: 'Wildlife', highlights: ['Tiger Safari', 'Elephant Herds', 'Nilgiri Biosphere', 'Kabini River', '200+ Bird Species', 'Jungle Lodges'], bestTime: 'Oct - May', duration: '2-3 Days', emoji: '🐘', img: '/bandipur.jpg' },
    { name: 'Nagarahole (Rajiv Gandhi National Park)', slug: 'nagarahole', desc: 'Explore the environs of Nagarahole — meaning \'Snake River\' in Kannada — one of South India\'s most pristine national parks. The park derives its name from the winding course of the Kabini River that flows through its forests, creating a stunning landscape of riverine habitats, dense bamboo groves, and tall deciduous trees. Nagarahole has an astonishing abundance of wildlife, especially the Asiatic elephant — the park supports one of the largest elephant populations in India along with tigers, leopards, wild dogs, and over 270 bird species. The backdrop of the distant misty blue Brahmagiri Mountains, the natural sounds of the jungle, the gurgling of streams and rivers make your visit a memorable experience. The park is managed by Jungle Lodges and Resorts with the Kabini River Lodge offering world-class wildlife tourism.', category: 'Wildlife', highlights: ['Tiger Reserve', 'Kabini River Lodge', 'Asian Elephants', 'Brahmagiri Mountains', 'Jungle Safari', 'Bird Watching'], bestTime: 'Oct - May', duration: '2-3 Days', emoji: '🐅', img: '/nagarahole.jpg' },
    { name: 'Dandeli', slug: 'dandeli', desc: 'The adventure capital of Karnataka, nestled in the dense forests of the Western Ghats along the mighty Kali River. Dandeli offers India\'s best white water rafting on thrilling rapids of the Kali River — an experience previously unavailable on this side of the Ganga. The Dandeli Wildlife Sanctuary is home to the endangered black panther, bison, elephants, and over 300 bird species, including the Great Hornbill. Adventure enthusiasts can enjoy kayaking, coracling, canoeing, and nature treks through pristine jungle trails. Nearby Syntheri Rocks — a spectacular 300-foot deep gorge carved by the Kaneri River — is a geological marvel. The Kavala Caves with their ancient limestone formations and the Supa Dam add to Dandeli\'s diverse attractions, making it a paradise for both adventure seekers and nature lovers.', category: 'Adventure & Wildlife', highlights: ['White Water Rafting', 'Kali River', 'Black Panther', 'Syntheri Rocks', 'Kavala Caves', 'Jungle Lodges'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🌊', img: '/dandeli.jpg' },
    { name: 'Gokarna', slug: 'gokarna', desc: 'This coastal town in Uttara Kannada district draws Hindu pilgrims, Sanskrit scholars, and beach buffs alike to its pristine shores along the Arabian Sea. The ancient Mahabaleshwara Temple — one of the seven sacred Mukti Kshetras in Hinduism — houses the Atmalinga, making Gokarna one of the most important pilgrimage centers in South India. But beyond its spiritual significance, Gokarna has become a legendary beach destination. Om Beach, shaped like the sacred \'Om\' symbol, is one of the most photographed beaches in India. Kudle Beach with its crescent-shaped golden sand, Half Moon Beach, and Paradise Beach — wedged between gigantic cliffs that protrude like delicate fingers into the sea — offer the perfect blend of adventure, serenity, and natural beauty. The beaches are accessible only through forested hiking trails, adding to their untouched charm.', category: 'Beach & Pilgrimage', highlights: ['Om Beach', 'Mahabaleshwara Temple', 'Kudle Beach', 'Paradise Beach', 'Half Moon Beach', 'Coastal Treks'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🏖️', img: '/gokarna-beach.jpg' },
    { name: 'Karwar', slug: 'karwar', desc: 'With gentle waves, miles of golden sand, rugged hill ranges, thick woods and acres of emerald foliage, Karwar has all the makings of a perfect holiday destination on the Karnataka coast. This port city inspired the great Indian poet Rabindranath Tagore to pen his first play when he visited in 1882, and visitors today understand why — the stunning Karwar Beach, the peaceful Rabindranath Tagore Beach, the nearby Kurmagad Island, and the Devbagh Beach Resort (operated by Jungle Lodges and Resorts) accessible only by boat offer a serene coastal escape. The Sadashivgad Fort with its panoramic views of the Arabian Sea, the Kali River estuary where it meets the ocean, and the world-class INS Kadamba naval base add to Karwar\'s unique character as a city where nature, history, and modernity converge.', category: 'Beach Town', highlights: ['Rabindranath Tagore Beach', 'Devbagh Beach Resort', 'Kurmagad Island', 'Sadashivgad Fort', 'Kali River Estuary', 'Golden Sands'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🏖️', img: '/karwar.jpg' },
    { name: 'Kemmanagundi', slug: 'kemmanagundi', desc: 'The picturesque hill station was the summer retreat of the King of Mysuru, and one visit explains why royalty chose this elevated paradise. Ringed by the Baba Budan Giri Range at 1,434 meters, Kemmanagundi is blessed with silver cascades, mountain streams, and lush vegetation that creates a landscape of extraordinary beauty. The spectacular sunset view from the Raj Bhavan (the royal summer residence) is a photographer\'s delight, painting the sky in shades of gold and crimson over the mist-covered valleys below. Kemmanagundi also offers many peaks to scale — including the challenging Z Point trek — and intricate jungle paths to explore through the Bhadra Wildlife Sanctuary that surrounds the hill station. The Hebbe Falls, Kalhatti Falls, and the Shola grasslands add to the natural splendor, making Kemmanagundi a paradise for trekkers and nature photographers.', category: 'Hill Station', highlights: ['Raj Bhavan Sunset Point', 'Z Point Trek', 'Hebbe Falls', 'Baba Budan Giri Range', 'Shola Grasslands', 'Royal Summer Retreat'], bestTime: 'Sep - Mar', duration: '1-2 Days', emoji: '🏔️', img: '/kemmanagundi.jpg' },
    { name: 'Kudremukh', slug: 'kudremukh', desc: 'Kudremukh or \'Horse Face Range\' gets its name from the unique shape of its peak at 1,894 meters — it resembles the face of a horse when viewed from a specific angle. Located in the heart of the Western Ghats and part of a UNESCO World Heritage Site, Kudremukh is a trekker\'s paradise offering some of the most scenic trails in South India. This wonderland of lush green forests interspersed with rivers, grassy slopes, captivating cascades, rare orchids, caves, ruins and traces of old civilizations amaze you as you trek your way through it. The Hanuman Gundi Falls, a spectacular waterfall deep in the forest accessible by a 1 km trek, and the Lakya Dam viewpoint surrounded by rolling green hills are highlights. The Kudremukh National Park is home to endangered species like the lion-tailed macaque and Malabar giant squirrel.', category: 'Hill Station & Trekking', highlights: ['Kudremukh Peak Trek', 'Hanuman Gundi Falls', 'Lakya Dam', 'Lion-tailed Macaque', 'UNESCO Western Ghats', 'Grassland Valleys'], bestTime: 'Oct - Feb', duration: '2 Days', emoji: '🏔️', img: '/kudremukh.jpg' },
    { name: 'Murudeshwara', slug: 'murudeshwara', desc: 'Home to the second tallest Shiva statue in the world — a magnificent 123-foot colossus towering over the Arabian Sea — Murudeshwara is one of Karnataka\'s most spectacular coastal destinations. The ancient Murudeshwara Temple, situated on a hilltop surrounded by the sea on three sides, is one of the five sacred places of Lord Shiva in the Hindu epic Ramayana. The 20-story Raja Gopura at the temple entrance is the tallest gopura in the world, adorned with intricate sculptures. The pristine Murudeshwara Beach offers stunning views of the Shiva statue against the backdrop of the setting sun, creating one of the most Instagram-worthy spectacles in India. Scuba diving at Netrani Island nearby — one of the best dive sites on India\'s west coast with crystal-clear waters and vibrant coral reefs — makes Murudeshwara a unique blend of spirituality, beauty, and adventure.', category: 'Beach & Pilgrimage', highlights: ['123ft Shiva Statue', 'Murudeshwara Temple', 'Tallest Gopura', 'Netrani Island Diving', 'Arabian Sea Views', 'Beach Photography'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/murudeshwara.jpg' },
    { name: 'Sringeri', slug: 'sringeri', desc: 'One of the most sacred pilgrimage centers in South India, Sringeri is home to the first of the four Amnaya Peethas (monasteries) established by the great philosopher Adi Shankaracharya in the 8th century. Nestled on the banks of the Tunga River in the lush Western Ghats, the Sharadamba Temple — dedicated to Goddess Saraswati — stands as the spiritual heart of the town. The ancient Vidyashankara Temple, built in the 14th century, is an architectural marvel with its 12 zodiac pillars that align with the sun\'s position throughout the year. The serene temple complex, surrounded by coconut palms and dense forests, hosts thousands of devotees and scholars of Vedanta philosophy. Sringeri also serves as the gateway to several beautiful Western Ghats destinations including Agumbe, Kudremukh, and the Hornadu temple.', category: 'Pilgrimage', highlights: ['Sharadamba Temple', 'Adi Shankaracharya Peetha', 'Vidyashankara Temple', 'Zodiac Pillars', 'Tunga River', 'Vedanta Philosophy Center'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/sringeri.jpg' },
    { name: 'Kollur Mookambika', slug: 'kollur', desc: 'The village of Kollur lies amid the green canopy of the Western Ghats, about 130 km from Mangaluru. Here, the Mookambika Temple — one of the seven most sacred spots of the coastal region — is dedicated to Goddess Mookambika, the deity of emotional power and strength. According to legend, Adi Shankaracharya himself installed the idol here, and the temple attracts millions of devotees from across South India. The stunning Kodachadri peak — part of the Mookambika Wildlife Sanctuary and a UNESCO World Heritage Site — is accessible via a challenging trek from Kollur, offering breathtaking views of the Arabian Sea on clear days. The ancient Sarvajna Peetha, where Adi Shankara is believed to have attained enlightenment, sits at the summit. The Arisina Gundi waterfall near the trekking trail adds to the natural beauty of this sacred destination.', category: 'Pilgrimage', highlights: ['Mookambika Temple', 'Kodachadri Peak Trek', 'Adi Shankaracharya', 'Sarvajna Peetha', 'Mookambika Wildlife Sanctuary', 'Arisina Gundi Falls'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/kollur.jpg' },
    { name: 'Basava Kalyana', slug: 'basava-kalyana', desc: 'Known as the Karmabhoomi of Basavanna, the revered 12th-century social reformer and philosopher who founded the Veerashaiva (Lingayat) movement. Located about 80 km from Bidar, Basava Kalyana was the capital city of the Chalukyas of Kalyana and served as the epicenter of a revolutionary social reform movement that challenged caste discrimination and championed equality. The city\'s attractions include the historic Basaveshwara Temple, the Anubhava Mantapa (the world\'s first parliamentary democracy where people of all castes and genders debated philosophy and social issues), and the magnificent fort built by the Chalukyas. The annual Basava Jayanthi celebrations draw hundreds of thousands of devotees. Nearby is the Chennabasaveshwara Temple at Haveri and the historic monuments from the Kalyani Chalukya period that showcase remarkable artistry and architectural innovation.', category: 'Heritage & Pilgrimage', highlights: ['Basaveshwara Temple', 'Anubhava Mantapa', 'Chalukya Fort', 'Veerashaiva Movement', 'Social Reform Heritage', 'Basava Jayanthi'], bestTime: 'Oct - Feb', duration: '1-2 Days', emoji: '🏛️', img: '/basava-kalyana.jpg' },
    { name: 'Jog Falls (Gerosoppa)', slug: 'jog-falls', desc: 'Bear witness to nature\'s headlong tumble as the Sharavati River takes a spectacular drop of 253 meters (830 feet) in four distinct cascades — Raja, Rani, Roarer, and Rocket — to create the second highest plunge waterfall in India and the highest untiered waterfall in the country. Located near Sagara in Shivamogga district, Jog Falls (also called Gerosoppa Falls) presents a breathtaking sight during the monsoon when the river swells to its full fury, sending clouds of mist high into the air that can be seen from kilometers away. The four cascades are named for their unique characteristics: Raja (the majestic), Rani (the graceful), Roarer (the thundering), and Rocket (the high-velocity). The view from the Watkins Platform offers the most panoramic perspective of all four cascades simultaneously. During peak monsoon, the falls create a natural amphitheater of sound and spray that is truly one of India\'s most spectacular natural wonders.', category: 'Waterfall', highlights: ['253m Plunge (2nd Highest India)', 'Raja-Rani-Roarer-Rocket Cascades', 'Watkins Platform Viewpoint', 'Monsoon Spectacle', 'Sharavati River', '4 Distinct Cascades'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/jog-falls.jpg' },
    { name: 'Shivanasamudra Falls', slug: 'shivanasamudra', desc: 'Discover nature\'s handiwork in the form of this tiny island-town, 65 km south-east of Mysuru, where the Cauvery River plummets from a height of 75 meters into a rocky gorge with a deafening roar — creating one of the most impressive waterfalls in South India. The falls are split into two segments — Gaganachukki and Bharachukki — separated by a small island, and during the monsoon they become a thundering spectacle of raw natural power. Shivanasamudra is also home to Asia\'s first hydro-electric project, commissioned in 1902, which powered the Kolar Gold Fields — making it a landmark in India\'s industrial history. The Barachukki viewpoint and the ancient Shiva temple near the falls add cultural significance to this natural wonder. The nearby Mekedatu (Goat\'s Leap) where the Cauvery flows through a narrow gorge is another geological marvel worth visiting.', category: 'Waterfall', highlights: ['Gaganachukki Falls', 'Bharachukki Falls', 'Asia\'s First Hydro-Electric Project', 'Cauvery River Gorge', 'Mekedatu (Goat\'s Leap)', '75m Plunge'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/shivanasamudra.jpg' },
    { name: 'Unchalli Falls (Lushington Falls)', slug: 'unchalli-falls', desc: 'A 5 km trek from Heggarne, a dreamy hamlet in Uttara Kannada District, through dense forests brings you to the picturesque Unchalli Falls — also known as Lushington Falls. The sound of the cataract hurtling down the hilly tract shatters the silence of the forests, making it an unforgettable sight. The waterfall cascades from a height of about 116 meters (381 feet) into a deep narrow gorge, surrounded by lush tropical forests of the Western Ghats. The trek to reach the falls is itself an adventure, winding through coffee plantations, spice gardens, and dense jungle where the sounds of exotic birds accompany every step. The nearby Kanakagundi viewpoint offers a breathtaking panoramic view of the falls and the surrounding valleys, making the Unchalli Falls one of the most rewarding trek destinations in Karnataka\'s adventure tourism circuit.', category: 'Waterfall & Trekking', highlights: ['116m Waterfall', 'Heggarne Forest Trek', 'Kanakagundi Viewpoint', 'Western Ghats Forest', 'Coffee Plantations', 'Kali River Tributary'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/unchalli-falls.jpg' },
    { name: 'BRT Wildlife Sanctuary', slug: 'brt-wildlife-sanctuary', desc: 'Discover a unique blend of a hill resort and wildlife sanctuary at Biligiri Rangaswamy Temple (BRT) Wildlife Sanctuary. Located at the confluence of the Western and Eastern Ghats, this sanctuary is home to the majestic Asiatic elephant, the endangered tiger, and over 250 species of birds. Don\'t miss the coffee estates, tribal Soliga hamlets, and the Vivekananda Girijana Kalyana Kendra which displays preserved tribal information and biodiversity of the region. There are many trekking trails including the one that leads up to Honnamati, the highest point of the range. The sanctuary gets its name from the ancient Biligiri Rangaswamy Temple perched atop the highest hill.', category: 'Wildlife', highlights: ['Biligiri Rangaswamy Temple', '250+ Bird Species', 'Soliga Tribal Hamlets', 'Honnamati Peak Trek', 'Coffee Estates', 'Vivekananda Girijana Kalyana Kendra'], bestTime: 'Oct - May', duration: '2 Days', emoji: '🐅', img: '/brt-wildlife.jpg' },
    { name: 'Ranganthittu Bird Sanctuary', slug: 'ranganthittu', desc: 'River Cauvery, near Mysuru, meanders around a string of tiny islets to form a splendid nesting site for waterfowl at Ranganthittu Bird Sanctuary. Experience the excitement of a boat ride that takes you close to birds as well as crocodiles basking on the riverbanks. Also spot flying foxes hanging from the highest branches of the ancient trees. The sanctuary is home to thousands of migratory birds including painted storks, Asian openbill storks, black-headed ibis, and spot-billed pelicans. It is one of the most important bird sanctuaries in India and a paradise for birdwatchers and nature photographers.', category: 'Wildlife', highlights: ['Boat Rides', 'Crocodiles', 'Migratory Birds', 'Painted Storks', 'Flying Foxes', 'Cauvery River Islets'], bestTime: 'Jun - Oct', duration: '1 Day', emoji: '🦅', img: '/ranganthittu.jpg' },
    { name: 'Gokak Falls', slug: 'gokak-falls', desc: 'Located 65 km from Belgaum, the Ghataprabha River takes a spectacular 170-foot leap over a rocky bed to create the magnificent Gokak Falls. The falls gets its name from the Goki trees that abound in the area. The historic Gokak suspension bridge, built in 1907, offers a thrilling vantage point from where visitors can feel the spray of the cascading water. The Gokak town nearby has an ancient Shiva temple and the monolithic monument of the Chalukya period. The sound of the roaring falls combined with the lush green surroundings creates an unforgettable experience.', category: 'Waterfall', highlights: ['170ft Plunge', 'Ghataprabha River', 'Historic Suspension Bridge', 'Goki Trees', 'Ancient Shiva Temple', 'Chalukya Monument'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/gokak-falls.jpg' },
    { name: 'Hebbe Falls', slug: 'hebbe-falls', desc: 'Hidden deep within the dense forests of the Baba Budang Giri Range near Chikmagalur, Hebbe Falls is one of Karnataka\'s most enchanting waterfalls. The falls cascade from a height of 168 meters in two distinct stages — Dodda Hebbe (Big Falls) and Chikka Hebbe (Small Falls) — creating a mesmerizing sight as the water crashes onto the rocks below. The trek through the coffee plantations and spice gardens to reach the falls is an adventure in itself. The surrounding forest is rich in biodiversity, and the cool mist from the falls provides a refreshing escape from the tropical heat.', category: 'Waterfall', highlights: ['168m Two-Stage Cascade', 'Baba Budan Giri Range', 'Coffee Plantation Trek', 'Dodda Hebbe & Chikka Hebbe', 'Forest Trail', 'Natural Pool'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/hebbe-falls.jpg' },
    { name: 'Agumbe', slug: 'agumbe', desc: 'Known as the "Cherrapunji of South India" for receiving some of the highest rainfall in India, Agumbe is a biodiversity hotspot and one of the last surviving lowland rainforest ecosystems in the Western Ghats. This small village in Shivamogga district gained fame as the setting for the iconic Malgudi Days TV series based on R.K. Narayan\'s stories. Agumbe is home to the Agumbe Rainforest Research Station, the world\'s longest-running King Cobra monitoring and research station. The stunning sunset viewpoint from Agumbe Ghats offers panoramic views of the Arabian Sea on clear days, while the nearby Barkana Falls (one of the tallest waterfalls in Karnataka) and Onake Abbi Falls add to the natural splendor.', category: 'Nature & Adventure', highlights: ['Highest Rainfall in South India', 'King Cobra Research Station', 'Malgudi Days Location', 'Barkana Falls', 'Arabian Sea Sunset Point', 'Rainforest Treks'], bestTime: 'Jul - Feb', duration: '1-2 Days', emoji: '🐍', img: '/agumbe.jpg' },
    { name: 'Kaup Beach & Lighthouse', slug: 'kaup', desc: 'Situated 12 km south of Udupi on the coastal belt along the West Coast National Highway, Kaup has a lovely beach with golden sand stretching along the Arabian Sea, a ruined fort, and an old 100-foot-high lighthouse that offers breathtaking panoramic views of the coastline. The lighthouse, built in 1901 by the British, is a beloved landmark and visitors can climb to the top for a stunning 360-degree view. The two ancient temples of Goddess Mariamma and the Jain Basadis here, though in ruins, are worth visiting for their historical significance. The pristine beach is perfect for evening walks and watching spectacular sunsets over the Arabian Sea.', category: 'Beach', highlights: ['100ft British Lighthouse', 'Golden Sand Beach', 'Panoramic Coastline Views', 'Ruined Fort', 'Ancient Temples', 'Arabian Sea Sunsets'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🏖️', img: '/kaup-beach.jpg' },
    { name: 'Malpe Beach & Port', slug: 'malpe', desc: 'Malpe is an important fishing centre and one of the most beautiful beach destinations on the Karnataka coast. The endless stretch of golden sand, graciously swaying palm trees, clear blue skies and the gentle murmur of the Arabian Sea set the perfect mood for an idyllic holiday. The beach is the gateway to the famous St. Mary\'s Island with its unique hexagonal basalt rock formations. Malpe\'s natural harbour, one of the major fishing ports of Karnataka, adds character to the town with colorful fishing boats and fresh seafood available at the shore. The nearby Daria Bahadurgad Fort on an island and the Balarama Temple add historical significance to this coastal paradise.', category: 'Beach Town', highlights: ['Fishing Port', 'Gateway to St. Mary\'s Island', 'Golden Sand Beach', 'Palm Trees', 'Fresh Seafood', 'Daria Bahadurgad Fort'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏖️', img: '/malpe-beach.jpg' },
    { name: 'St. Mary\'s Island', slug: 'st-marys-island', desc: 'Located 6 km from Malpe across the Arabian Sea, the 300-meter-long and 100-meter-wide palm-fringed St. Mary\'s Island is a geological wonder. Famous for its unique hexagonal basalt column rock formations — created by volcanic activity millions of years ago — the island has been declared a National Geological Monument by the Geological Survey of India. The island bears the cross placed by Vasco da Gama when he landed here in 1498, making it a site of great historical significance. Accessible only by a 15-minute boat ride from Malpe, the island offers pristine untouched beaches, crystal-clear turquoise waters, and a serene atmosphere that makes it one of the most photogenic destinations on India\'s western coast.', category: 'Island & Heritage', highlights: ['Hexagonal Basalt Columns', 'National Geological Monument', 'Vasco da Gama Landing Site', '1498 Cross', 'Boat Ride from Malpe', 'Crystal Clear Waters'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🏝️', img: '/st-marys-island.jpg' },
    { name: 'Irrupu Falls (Iruppu Falls)', slug: 'irrupu-falls', desc: 'Nestling beside the Nagarahole National Park in the Brahmagiri Range of the Western Ghats, Irrupu Falls presents a stunning sight during the monsoons and post-monsoon months. The falls plunge 170 feet in two distinct stages through the dense tropical forest, creating a natural pool at the base. According to Hindu legend, Lord Rama and Lakshmana passed through this area during their search for Sita, and Rama shot an arrow into the Brahmagiri Hills bringing forth the river Lakshmana Tirtha that feeds the falls. A sacred Shiva temple (Rameshwara Temple) near the falls attracts thousands of pilgrims. The trek through the Brahmagiri Wildlife Sanctuary to reach the falls is a delightful experience rich in birdlife and endemic flora.', category: 'Waterfall & Pilgrimage', highlights: ['170ft Two-Stage Falls', 'Brahmagiri Range', 'Rameshwara Temple', 'Lakshmana Tirtha River', 'Nagarahole Proximity', 'Forest Trek'], bestTime: 'Jul - Oct', duration: '1 Day', emoji: '💧', img: '/irrupu-falls.jpg' },
    { name: 'Bylakuppe (Tibetan Settlement)', slug: 'bylakuppe', desc: 'One of the largest Tibetan refugee settlements in South India, Bylakuppe near Kushalnagar in Kodagu district is a vibrant cultural enclave that transports visitors to a miniature Tibet. The settlement is dotted with several magnificent monasteries; the main ones being the Great Gompa of Sera Jey and Sera Mey — replicas of the original Sera Monastery in Lhasa, Tibet. The Namdroling Monastery, also known as the Golden Temple, features a stunning 60-foot-tall golden Buddha statue flanked by equally impressive statues of Padmasambhava and Amitayus. The monastery\'s ornate prayer hall with its intricate Tibetan murals, the sound of chanting monks, and the spinning prayer wheels create a deeply spiritual atmosphere. The settlement also has an enormous prayer hall and the Tashi Lhunpo Monastery, renowned as the seat of the Panchen Lama.', category: 'Cultural & Spiritual', highlights: ['Golden Temple (Namdroling)', '60ft Buddha Statue', 'Sera Jey Monastery', 'Tibetan Prayer Wheels', 'Sera Mey Monastery', 'Tashi Lhunpo Monastery'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🛕', img: '/bylakuppe.jpg' },
    { name: 'Kittur Chennamma Fort', slug: 'kittur', desc: 'Located on the Pune-Bengaluru highway, the Kittur Fort stands as a powerful testament to the great freedom struggle led by the legendary Rani Chennamma of Kittur against the British East India Company in 1824 — one of India\'s earliest women freedom fighters, predating Rani Lakshmibai of Jhansi by three decades. The tiny town of Kittur, about 50 km from Belgaum and 32 km from Dharwad, with its dilapidated palace, monuments, statues and horse tongas (rickshaws) evoke the glories of a bygone era. The fort was the site of a fierce battle where Rani Chennamma and her brave soldiers fought against the British forces. The archaeological museum inside the fort complex displays artifacts, weapons, and paintings from the Kittur era.', category: 'Heritage & Fort', highlights: ['Rani Chennamma Memorial', 'Freedom Struggle Heritage', 'Archaeological Museum', 'Historical Fort', 'Palace Ruins', 'Monuments & Statues'], bestTime: 'Oct - Feb', duration: '1 Day', emoji: '🏰', img: '/kittur-fort.jpg' },
    { name: 'Nandi Hills', slug: 'nandi-hills', desc: 'Perched at an altitude of 1,478 meters, Nandi Hills (also known as Nandidurga) is one of the most popular hill stations near Bengaluru, just 60 km from the city. The ancient hill fortress was built by Tipu Sultan and later used by the British as a summer retreat. The hill gets its name from the magnificent Nandi (bull) statue carved from a single monolithic rock at the Yoga Nandeeshwara Temple on the summit — one of the oldest temples in Karnataka, dedicated to Lord Shiva. Tipu\'s Drop, a 600-meter cliff face from where Tipu Sultan supposedly dropped prisoners, offers vertigo-inducing views of the plains below. The breathtaking sunrise and sunset views from Tippu\'s Point, the scenic Amrita Sarovar lake, and the refreshing mountain air make Nandi Hills a perfect weekend getaway from Bengaluru.', category: 'Hill Station', highlights: ['Yoga Nandeeshwara Temple', 'Monolithic Nandi Statue', 'Tipu Sultan Fort', 'Sunrise Point', 'Tipu\'s Drop', 'Amrita Sarovar Lake'], bestTime: 'Sep - Feb', duration: '1 Day', emoji: '🏔️', img: '/nandi-hills.jpg' },
    { name: 'BR Hills (Biligiri Rangaswamy Hills)', slug: 'br-hills', desc: 'The Biligiri Rangaswamy Hills (BR Hills) form a unique ecological corridor connecting the Eastern and Western Ghats at an altitude of 1,800 meters. The hills get their name from the ancient Biligiri Rangaswamy Temple perched on a white cliff at the highest point. The K Gudi Wilderness Camp, operated by Jungle Lodges and Resorts, offers an unparalleled wildlife experience where you can spot elephants, tigers, leopards, gaurs, and over 270 species of birds. The region is home to the Soliga tribal community, one of the oldest indigenous forest-dwelling communities in India. The breathtaking view of the surrounding forests, valleys, and distant mountain ranges from the temple summit, combined with the pristine natural environment, makes BR Hills a paradise for nature lovers, wildlife photographers, and those seeking spiritual solace.', category: 'Wildlife & Hill Station', highlights: ['K Gudi Wilderness Camp', 'Biligiri Rangaswamy Temple', 'Elephant & Tiger Safaris', '270+ Bird Species', 'Soliga Tribal Community', 'Eastern-Western Ghats Corridor'], bestTime: 'Oct - May', duration: '2 Days', emoji: '🐘', img: '/br-hills.jpg' },
    { name: 'Maravanthe Beach', slug: 'maravanthe', desc: 'One of the most scenic beach destinations on the Karnataka coast, Maravanthe offers a unique and breathtaking landscape where the National Highway 66 runs between the Arabian Sea on one side and the Saurpanika River on the other — creating a picture-perfect panorama that is often called one of the most beautiful drives in India. The golden sand beach stretches along the Arabian Sea with coconut palm groves providing natural shade, while the Kodachadri hills are visible in the distance on clear days. The nearby Baindoor town offers access to the Ottinene beach with its stunning sunset views. The serene atmosphere, gentle waves, and the unique highway-between-water-and-sea geography make Maravanthe a must-visit coastal destination.', category: 'Beach', highlights: ['Highway Between Sea & River', 'Saurpanika River', 'Golden Sand Beach', 'Scenic Drive', 'Ottinene Sunset Point', 'Coconut Palm Groves'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🏖️', img: '/maravanthe.jpg' },
    { name: 'Kodachadri Peak', slug: 'kodachadri', desc: 'Part of the Western Ghats in Shivamogga district at an altitude of 1,343 meters, Kodachadri Peak is a UNESCO World Heritage Site and one of the most stunning trekking destinations in Karnataka. The peak forms the backdrop of the famous Mookambika Temple at Kollur and is part of the Mookambika Wildlife Sanctuary. The challenging 12-km trek through dense tropical forests, rolling grasslands, and misty mountain trails rewards trekkers with breathtaking panoramic views of the Arabian Sea on clear days. The ancient Sarvajna Peetha at the summit, where Adi Shankaracharya is believed to have attained enlightenment, adds deep spiritual significance. The nearby Hidlumane Falls and the Arisina Gundi waterfall along the trekking route add to the natural splendor of this magnificent peak.', category: 'Trekking Peak', highlights: ['UNESCO Western Ghats', 'Sarvajna Peetha (Adi Shankaracharya)', 'Arabian Sea View', '12km Forest Trek', 'Mookambika Wildlife Sanctuary', 'Hidlumane Falls'], bestTime: 'Sep - Feb', duration: '1-2 Days', emoji: '🏔️', img: '/kodachadri.jpg' },
  ],
};

export const KERALA: StateData = {
  name: 'Kerala', slug: 'kerala', coverImg: '/states/kerala-cover.jpg',
  tagline: "God's Own Country", tagColor: 'text-cyan-400', icon: '🛶', accentColor: 'cyan',
  heroDesc: 'Backwaters of Alleppey, tea gardens of Munnar, wildlife of Thekkady, beaches of Kovalam — experience paradise on earth.',
  places: [
    { name: 'Thiruvananthapuram', slug: 'thiruvananthapuram', desc: 'The capital city of Kerala, home to the iconic Sri Padmanabhaswamy Temple — the world\'s richest religious institution with treasures worth billions. Beautiful Kovalam Beach with its crescent-shaped shoreline, the historic Napier Museum and Zoological Garden, the majestic Kanakakunnu Palace, and the serene Veli Tourist Village where the lake meets the Arabian Sea make this city a perfect blend of heritage, culture, and tropical beauty.', category: 'Capital City', highlights: ['Padmanabhaswamy Temple', 'Kovalam Beach', 'Napier Museum', 'Veli Tourist Village', 'Kanakakunnu Palace', 'Shanghumukham Beach'], bestTime: 'Sep - Mar', duration: '2-3 Days', emoji: '🏙️', img: '/kovalam-beach.jpg' },
    { name: 'Kochi', slug: 'kochi', desc: 'Queen of the Arabian Sea and Kerala\'s commercial capital. Famous for the iconic Chinese Fishing Nets — a legacy of ancient trade with China, the beautiful Dutch Palace with its Ramayana murals, the 1568 Jewish Synagogue (oldest in the Commonwealth), the charming Fort Kochi heritage zone with its colonial buildings and street art, vibrant Marine Drive promenade, and a thriving arts, culinary, and shopping scene with incredible seafood.', category: 'Metro City', highlights: ['Chinese Fishing Nets', 'Fort Kochi', 'Jewish Synagogue', 'Marine Drive', 'Dutch Palace', 'Bolghatty Palace'], bestTime: 'Sep - Mar', duration: '2-3 Days', emoji: '🏙️', img: '/kochi-harbor.jpg' },
    { name: 'Kozhikode', slug: 'kozhikode', desc: 'Historic city where Portuguese explorer Vasco da Gama first landed in India in 1498. Known as the spice capital of Kerala, famous for its unique Malabar cuisine — from the legendary Kozhikode biryani to the sweet Kozhikode halwa and banana chips. The beautiful Kozhikode Beach, historic Kappad Beach (Gama\'s landing spot), the charming Mananchira Square, and the famous SM Street (Sweet Meat Street) for shopping.', category: 'Historic City', highlights: ['Kozhikode Beach', 'Kappad Beach', 'Mananchira Square', 'Sweet Street', 'Beypore Shipyard', 'Kadalundi Bird Sanctuary'], bestTime: 'Sep - Mar', duration: '2 Days', emoji: '🏙️', img: '/kozhikode-beach.jpg' },
    { name: 'Alappuzha', slug: 'alappuzha', desc: 'The Venice of the East — famous worldwide for its enchanting backwater houseboat cruises through a network of serene canals, lagoons, and lakes. The thrilling Nehru Trophy Snake Boat Race held every August draws hundreds of thousands of spectators. Nearby Kumarakom Bird Sanctuary on Vembanad Lake is a paradise for birdwatchers, while the beautiful Marari Beach offers peaceful coastal relaxation away from the crowds.', category: 'Backwaters', highlights: ['Houseboat Cruises', 'Nehru Trophy Boat Race', 'Kumarakom', 'Marari Beach', 'Vembanad Lake', 'Pathiramanal Island'], bestTime: 'Sep - Mar', duration: '2-3 Days', emoji: '🛶', img: '/alleppey-backwater.jpg' },
    { name: 'Kollam', slug: 'kollam', desc: 'Gateway to the famous Kerala backwaters and the starting point of the scenic Ashtamudi Lake houseboat cruises — Kerala\'s second largest lake shaped like eight arms. Known for cashew processing, ancient Thangassery Lighthouse built by the British in 1902, the spectacular Jatayu Earth Center featuring the world\'s largest bird sculpture, and beautiful backwater villages that showcase authentic Kerala life.', category: 'Backwaters', highlights: ['Ashtamudi Lake', 'Thangassery Lighthouse', 'Jatayu Earth Center', 'Backwater Cruises', 'Thenmala Ecotourism', 'Palaruvi Falls'], bestTime: 'Sep - Mar', duration: '2 Days', emoji: '🛶', img: '/alleppey-backwater.jpg' },
    { name: 'Munnar', slug: 'munnar', desc: 'One of India\'s most beautiful hill stations at 1,600 meters elevation, with endless tea gardens carpeting rolling hills as far as the eye can see. The misty Eravikulam National Park is home to the endangered Nilgiri Tahr, while Mattupetty Dam offers boating amid stunning scenery. The Kolukkumalai Tea Estate — the highest tea plantation in the world — and Top Station viewpoint with views stretching to the neighboring state make Munnar truly magical.', category: 'Hill Station', highlights: ['Tea Gardens', 'Eravikulam National Park', 'Mattupetty Dam', 'Top Station', 'Kolukkumalai', 'Echo Point'], bestTime: 'Sep - May', duration: '2-3 Days', emoji: '🏔️', img: '/munnar-tea.jpg' },
    { name: 'Kannur', slug: 'kannur', desc: 'Land of Theyyam — Kerala\'s most mystical and ancient ritual art form where performers embody divine spirits in elaborate costumes and face paint. Famous for pristine beaches like Payyambalam and Muzhappilangad (India\'s longest drive-in beach), the historic St. Angelo Fort built by the Portuguese in 1505, ancient handloom weaving traditions producing world-famous Kannur cotton, and the beautiful Arakkal Museum showcasing Kerala\'s only Muslim royal family.', category: 'Coastal City', highlights: ['Theyyam Ritual', 'Payyambalam Beach', 'St. Angelo Fort', 'Muzhappilangad Beach', 'Arakkal Museum', 'Parassinikkadavu Temple'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🏖️', img: '/kannur-beach.jpg' },
    { name: 'Thrissur', slug: 'thrissur', desc: 'Cultural capital of Kerala and home to the spectacular Thrissur Pooram — the greatest temple festival in Kerala, featuring decorated elephants, traditional percussion ensembles (Panchavadyam), and a magnificent fireworks display that draws millions. The sacred Guruvayur Sree Krishna Temple, Kerala Kalamandalam (premier performing arts institution), Vadakkumnathan Temple with its classical Kerala architecture, and the vibrant Swaraj Round make Thrissur the cultural heartbeat of Kerala.', category: 'Cultural Capital', highlights: ['Thrissur Pooram', 'Guruvayur Temple', 'Vadakkumnathan Temple', 'Kalamandalam', 'Athirapally Falls', 'Peechi Dam'], bestTime: 'Sep - Mar', duration: '2-3 Days', emoji: '🎭', img: '/thrissur-temple.jpg' },
    { name: 'Palakkad', slug: 'palakkad', desc: 'The granary of Kerala with vast green paddy fields stretching to the horizon. The stunning Palakkad Gap — a 32-kilometer pass through the Western Ghats — creates a unique microclimate that makes this region exceptionally fertile. The beautiful Malampuzha Dam with its rock garden, rope way, and aquarium, the pristine Silent Valley National Park (one of the last undisturbed stretches of South Western Ghats tropical evergreen forests), and the ancient Jainmedu Temple make Palakkad special.', category: 'Gateway to Kerala', highlights: ['Palakkad Gap', 'Malampuzha Dam', 'Silent Valley NP', 'Jainmedu Temple', 'Nelliampathy Hills', 'Parambikulam Tiger Reserve'], bestTime: 'Sep - Mar', duration: '2 Days', emoji: '🌿', img: '/wayanad-hills.jpg' },
    { name: 'Kasaragod', slug: 'kasaragod', desc: 'Northernmost district of Kerala known for the magnificent Bekal Fort — Kerala\'s largest and best-preserved fort, rising 130 feet above the Arabian Sea with stunning panoramic views. Pristine beaches, rich folk art forms like Theyyam and Yakshagana, the beautiful Chandragiri River, and the lush Ranipuram Hills offering trekking opportunities through forest trails make Kasaragod an offbeat gem waiting to be discovered.', category: 'Coastal Town', highlights: ['Bekal Fort', 'Bekal Beach', 'Chandragiri Fort', 'Ranipuram Hills', 'Ananthapura Lake Temple', 'Kottancheri Hills'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🏖️', img: '/bekal-fort.jpg' },
    { name: 'Vadakara', slug: 'vadakara', desc: 'Historic coastal town and the birthplace of the legendary warrior Thacholi Othenan, celebrated in the famous Vadakkanpattukal (Northern Ballads of Kerala). Famous for beautiful beaches, the ancient Lokanarkavu Temple associated with the warrior traditions, and the unique martial art culture of Kalarippayattu — one of the oldest fighting systems in the world with training centers that attract international martial arts enthusiasts.', category: 'Coastal Town', highlights: ['Lokanarkavu Temple', 'Kozhikode Beach', 'Kalarippayattu Centers', 'Vatakara Fort', 'Sand Banks Beach', 'Velliyamkallu'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏖️', img: '/kannur-beach.jpg' },
    { name: 'Malappuram', slug: 'malappuram', desc: 'Rich in cultural heritage with beautiful hill stations, historic mosques, and lush green landscapes. The lush Kadalundi Bird Sanctuary at the estuary of the Kadalundi River is a haven for migratory birds. The Nilambur Teak Museum showcases Kerala\'s historic teak plantations, while Kottakkunnu offers beautiful sunset views. Known as the land of great poets and the birthplace of Malayalam literature.', category: 'Cultural Town', highlights: ['Kadalundi Bird Sanctuary', 'Nilambur Teak Museum', 'Kottakkunnu', 'Tanur Beach', 'Angadipuram Temple', 'Nedumkayam'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🎭', img: '/wayanad-hills.jpg' },
    { name: 'Kottayam', slug: 'kottayam', desc: 'The land of latex, letters, and lakes — known as the literary capital of Kerala with a 100% literacy rate. Famous for the beautiful Vembanad Lake backwaters, lush rubber plantations, ancient churches including the 450-year-old St. Mary\'s Church (Valiyapally), the stunning Kumarakom Bird Sanctuary, and the beautiful Ettumanoor Mahadeva Temple with its exquisite Dravidian murals and the legendary Ezharaponnana (seven and a half elephants) offering.', category: 'Backwaters', highlights: ['Vembanad Lake', 'Kumarakom Bird Sanctuary', 'Ettumanoor Temple', 'Rubber Plantations', 'St. Mary\'s Church', 'Ilaveezhapoonchira'], bestTime: 'Sep - Mar', duration: '2 Days', emoji: '🛶', img: '/alleppey-backwater.jpg' },
  ],
};

export const TAMIL_NADU: StateData = {
  name: 'Tamil Nadu', slug: 'tamilnadu', coverImg: '/states/tamilnadu-cover.jpg',
  tagline: 'Temple Heritage', tagColor: 'text-purple-400', icon: '🛕', accentColor: 'purple',
  heroDesc: 'Ancient temples, hill stations, French colonies, and pristine beaches — experience the cultural heart of South India.',
  places: [
    { name: 'Chennai', slug: 'chennai', desc: 'India\'s cultural capital and gateway to South India. Home to the world\'s second longest urban beach — Marina Beach stretching 13 kilometers along the Bay of Bengal. Stunning temples like the colorful Kapaleeshwarar Temple in Mylapore, British-era Fort St. George (first British fortress in India), the Gothic San Thome Basilica built over the tomb of St. Thomas the Apostle, vibrant arts scene, and the famous South Indian film industry (Kollywood).', category: 'Capital City', highlights: ['Marina Beach', 'Kapaleeshwarar Temple', 'Fort St. George', 'San Thome Basilica', 'Guindy National Park', 'Valluvar Kottam'], bestTime: 'Nov - Feb', duration: '2-3 Days', emoji: '🏙️', img: '/chennai-marina.jpg' },
    { name: 'Madurai', slug: 'madurai', desc: 'One of India\'s oldest continuously inhabited cities (over 2,500 years), home to the spectacular Meenakshi Amman Temple with its towering gopurams covered in thousands of exquisitely detailed colorful sculptures of gods, goddesses, and mythical creatures. The grand Thirumalai Nayak Palace with its massive pillars and celestial decorations, the Gandhi Museum, and the sacred Vaigai River flowing through the heart of the city make Madurai the cultural soul of Tamil Nadu.', category: 'Temple City', highlights: ['Meenakshi Amman Temple', 'Thirumalai Nayak Palace', 'Gandhi Museum', 'Vaigai River', 'Thiruparankundram Temple', 'Alagar Koyil'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🛕', img: '/madurai-temple.jpg' },
    { name: 'Coimbatore', slug: 'coimbatore', desc: 'The Manchester of South India — a major textile and manufacturing hub nestled at the foothills of the Western Ghats. Known as the gateway to popular hill stations Ooty and Valparai, with excellent educational institutions, beautiful temples like the ancient Marudhamalai Murugan Temple perched on a hill, the scenic Siruvani Waterfalls known for its sweet-tasting water, and the famous Black Thunder water theme park.', category: 'Metro City', highlights: ['Marudhamalai Temple', 'Siruvani Waterfalls', 'VOC Park', 'Black Thunder', 'Ooty Gateway', 'Adiyogi Shiva Statue'], bestTime: 'Sep - Feb', duration: '2 Days', emoji: '🏙️', img: '/coimbatore-temple.jpg' },
    { name: 'Ooty', slug: 'ooty', desc: 'Queen of the Nilgiris and one of India\'s most beloved hill stations at 2,240 meters elevation. Famous for the charming toy train ride through 16 tunnels and 250 bridges on the Nilgiri Mountain Railway (UNESCO World Heritage), the beautiful Government Botanical Garden with 1,000+ plant species, boating on the serene Ooty Lake, and the breathtaking Dodabetta Peak — highest point in the Nilgiris offering panoramic views of three states.', category: 'Hill Station', highlights: ['Ooty Toy Train', 'Botanical Garden', 'Dodabetta Peak', 'Ooty Lake', 'Coonoor', 'Rose Garden'], bestTime: 'Apr - Jun, Sep - Nov', duration: '2-3 Days', emoji: '🏔️', img: '/ooty.jpg' },
    { name: 'Rameswaram', slug: 'rameswaram', desc: 'One of the holiest pilgrimage sites in India and one of the four sacred Char Dham sites. Home to the Ramanathaswamy Temple with the world\'s longest temple corridor — 1,220 meters with 1,212 ornate pillars. The engineering marvel Pamban Bridge (India\'s first sea bridge) connecting the island to mainland India over the turquoise waters. The mystical Dhanushkodi — a ghost town destroyed by the 1964 cyclone — and the sacred Agni Theertham where pilgrims perform rituals make Rameswaram deeply spiritual.', category: 'Pilgrimage', highlights: ['Ramanathaswamy Temple', 'Pamban Bridge', 'Dhanushkodi Ghost Town', 'Agni Theertham', 'APJ Abdul Kalam Memorial', 'Five-faced Hanuman Temple'], bestTime: 'Oct - Apr', duration: '2 Days', emoji: '🛕', img: '/rameswaram.jpg' },
    { name: 'Kanyakumari', slug: 'kanyakumari', desc: 'The southernmost tip of mainland India where three great water bodies — the Arabian Sea, Bay of Bengal, and Indian Ocean — dramatically converge. Famous for the Vivekananda Rock Memorial accessible by ferry, where Swami Vivekananda meditated, the towering 133-foot Thiruvalluvar Statue on a neighboring island, the breathtaking sunrise and sunset views (unique for watching both from the same point), and the beautiful Gandhi Memorial built where his ashes were kept before immersion.', category: 'Coastal Town', highlights: ['Vivekananda Rock Memorial', 'Thiruvalluvar Statue', 'Sunrise Point', 'Gandhi Memorial', 'Suchindram Temple', 'Padmanabhapuram Palace'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🌅', img: '/kanyakumari.jpg' },
    { name: 'Pondicherry', slug: 'pondicherry', desc: 'A charming former French colony with colorful colonial-era buildings, tree-lined boulevards, French cafes and bakeries serving authentic croissants and espresso, the famous Sri Aurobindo Ashram, the utopian Auroville Township with its golden Matrimandir meditation sphere, and a unique Franco-Tamil cultural blend visible in the architecture, cuisine, and lifestyle. The Promenade Beach, Auroville Beach, and the vibrant French Quarter make Pondicherry unlike any other Indian city.', category: 'French Colony', highlights: ['Promenade Beach', 'Auroville', 'French Quarter', 'Sri Aurobindo Ashram', 'Paradise Beach', 'Matrimandir'], bestTime: 'Oct - Mar', duration: '2-3 Days', emoji: '🏘️', img: '/pondicherry.jpg' },
    { name: 'Tiruchirapalli', slug: 'trichy', desc: 'Home to the iconic Rock Fort Temple perched dramatically on an 83-meter-high ancient rock — one of the oldest rock formations in the world at 3.8 billion years. The massive Srirangam Temple island complex is the largest functioning Hindu temple in the world. The stunning Jambukeswarar Temple (one of the five Pancha Bhoota Stalas representing water), the ancient Kallanai Dam (built 2,000 years ago — one of the oldest water-diversion structures still in use), and the beautiful Mukkombu make Trichy extraordinary.', category: 'Temple City', highlights: ['Rock Fort Temple', 'Srirangam Temple', 'Jambukeswarar Temple', 'Kallanai Dam', 'Mukkombu', 'St. Joseph\'s Church'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🛕', img: '/rockfort-temple.jpg' },
    { name: 'Thanjavur', slug: 'thanjavur', desc: 'The rice bowl of Tamil Nadu and home to the magnificent Brihadeeswara Temple — a UNESCO World Heritage Site completed in 1010 AD by Rajaraja Chola. Its 66-meter vimana (tower) was the tallest in India for centuries. Famous for the exquisite Tanjore paintings (gold-leaf artwork), classical music and dance traditions, the grand Maratha Palace complex housing the Saraswathi Mahal Library with rare ancient manuscripts, and the beautiful Schwartz Church.', category: 'Heritage City', highlights: ['Brihadeeswara Temple', 'Tanjore Palace', 'Saraswathi Mahal Library', 'Tanjore Paintings', 'Schwartz Church', 'Punniyamurthi Temple'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏛️', img: '/thanjavur-temple.jpg' },
    { name: 'Kodaikanal', slug: 'kodaikanal', desc: 'Princess of Hill Stations — a beautiful mountain retreat at 2,133 meters in the Palani Hills. The star-shaped Kodaikanal Lake with rowboats and cycling paths, the scenic Coaker\'s Walk — a 1-km paved path along the cliff edge offering breathtaking valley views, Bryant Park with its rare flowering plants, Silver Cascade Falls, the misty Pine Forest with towering trees, and the beautiful Pillar Rocks are natural wonders that make Kodaikanal a perfect romantic getaway.', category: 'Hill Station', highlights: ['Kodaikanal Lake', 'Coaker\'s Walk', 'Pine Forest', 'Silver Cascade Falls', 'Pillar Rocks', 'Guna Caves'], bestTime: 'Apr - Jun, Sep - Oct', duration: '2-3 Days', emoji: '🏔️', img: '/kodaikanal.jpg' },
    { name: 'Mahabalipuram', slug: 'mahabalipuram', desc: 'UNESCO World Heritage Site with stunning 7th-century Pallava rock-cut temples and shore temples. The Five Rathas — monolithic rock temples carved from single boulders, each shaped like a different chariot — showcase extraordinary craftsmanship. The magnificent Arjuna\'s Penance — the world\'s largest bas-relief measuring 27m x 9m carved on a single rock face, the beautiful Shore Temple standing dramatically against the Bay of Bengal, and the golden Mahabalipuram Beach make this an archaeologist\'s paradise.', category: 'Heritage', highlights: ['Shore Temple', 'Five Rathas', 'Arjuna\'s Penance', 'Mahabalipuram Beach', 'Krishna\'s Butter Ball', 'Tiger\'s Cave'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏛️', img: '/mahabalipuram-temple.jpg' },
    { name: 'Vellore', slug: 'vellore', desc: 'Known for the magnificent Golden Temple (Sripuram) — a stunning spiritual park with a temple covered in 1.5 tons of pure gold foil, set amid beautifully landscaped gardens and a star-shaped path. The historic 16th-century Vellore Fort built by the Vijayanagara kings, the ancient Jalakandeswarar Temple inside the fort with its stunning Dravidian architecture, and the prestigious VIT University make Vellore a unique blend of spiritual grandeur, heritage, and education.', category: 'Temple City', highlights: ['Golden Temple Sripuram', 'Vellore Fort', 'Jalakandeswarar Temple', 'VIT University', 'Amirthi Zoological Park', 'Yelagiri Hills'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/vellore-golden-temple.jpg' },
    { name: 'Salem', slug: 'salem', desc: 'A major city surrounded by beautiful hills and known as the Steel City of Tamil Nadu. Gateway to the stunning Yercaud hill station at 1,515 meters — called the Poor Man\'s Ooty — with its beautiful Yercaud Lake, Killiyur Falls, and Lady\'s Seat viewpoint. Famous for mango orchards producing some of India\'s finest mangoes, the picturesque Mettur Dam, the ancient Kailasanathar Temple, and the 1008 Lingam Temple at Poiman Karadu.', category: 'Industrial City', highlights: ['Yercaud Hill Station', 'Mettur Dam', 'Kailasanathar Temple', 'Mango Orchards', '1008 Lingam Temple', 'Kurumbapatti Zoo'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🏙️', img: '/salem-yercaud.jpg' },
    { name: 'Tirunelveli', slug: 'tirunelveli', desc: 'Ancient temple city famous for the magnificent Nellaiappar Temple complex dedicated to Lord Shiva, with its musical pillars that produce the seven notes of Indian classical music. The spectacular Courtallam Falls — known as the Spa of South India — features nine waterfalls where the Western Ghats streams cascade from varying heights, believed to have medicinal properties. The legendary Tirunelveli halwa, made with ghee and wheat milk, has been a culinary icon for over a century.', category: 'Temple City', highlights: ['Courtallam Falls', 'Nellaiappar Temple', 'Tirunelveli Halwa', 'Manimuthar Falls', 'Papanasam Temple', 'Agasthiyar Falls'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🛕', img: '/states/tamilnadu-cover.jpg' },
    { name: 'Tiruppur', slug: 'tiruppur', desc: 'The knitwear capital of India, producing garments for global brands like Nike, Adidas, and H&M. A rapidly growing industrial city that exports textiles worth billions worldwide. Despite its industrial focus, Tiruppur has beautiful temples like the ancient Avinashiappar Temple, the scenic Noyyal River, and serves as a gateway to the beautiful Annamalai hills and the stunning Palani Murugan Temple — one of the six abodes of Lord Murugan.', category: 'Industrial City', highlights: ['Textile Industry', 'Noyyal River', 'Avinashi Temple', 'Palani Temple Access', 'Amaravathi Dam', 'Thirumoorthy Hills'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏙️', img: '/coimbatore-temple.jpg' },
    { name: 'Dindigul', slug: 'dindigul', desc: 'Known for the mighty Dindigul Fort perched atop a 280-meter rock hill, built by the Madurai Nayak kings and later strengthened by Hyder Ali and Tipu Sultan. Famous across South India for the delicious Dindigul biryani — cooked with seeraga samba rice and unique spice blends. Gateway to the beautiful Kodaikanal hill station, the lush Sirumalai Hills with their banana plantations, and ancient temples like the Abirami Amman Temple.', category: 'Industrial City', highlights: ['Dindigul Fort', 'Kodaikanal Gateway', 'Sirumalai Hills', 'Dindigul Biryani', 'Natham Hill', 'Kamarajar Lake'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏙️', img: '/kodaikanal.jpg' },
    { name: 'Pollachi', slug: 'pollachi', desc: 'A charming town known as the coconut capital of Tamil Nadu, surrounded by lush coconut, areca nut, and sugarcane plantations. Famous as the gateway to Topslip in the Anamalai Tiger Reserve — one of the best places in South India for wildlife spotting including elephants, tigers, and the endangered lion-tailed macaque. The beautiful Aliyar Dam with its park and garden, the Masani Amman Temple, and the scenic Valparai hill road with its 40 hairpin bends make Pollachi a nature lover\'s paradise.', category: 'Nature Town', highlights: ['Topslip Tiger Reserve', 'Anaimalai Hills', 'Aliyar Dam', 'Masani Amman Temple', 'Valparai Hill Road', 'Monkey Falls'], bestTime: 'Oct - Mar', duration: '2 Days', emoji: '🌿', img: '/kodaikanal.jpg' },
    { name: 'Kumbakonam', slug: 'kumbakonam', desc: 'Temple town of Tamil Nadu with over 188 temples within the city limits, making it one of the most temple-dense cities in the world. Famous as the location for the sacred Kumbh Mela (Mahamaham) held every 12 years when millions of pilgrims bathe in the Mahamaham Tank. The magnificent Airavatesvara Temple at nearby Darasuram is a UNESCO World Heritage Site with exquisite Chola architecture. The city is also legendary for its Kumbakonam Degree Coffee — one of India\'s finest filter coffees.', category: 'Temple Town', highlights: ['Airavatesvara Temple (UNESCO)', 'Mahamaham Tank', 'Sarangapani Temple', 'Kumbakonam Coffee', 'Adi Kumbeswarar Temple', 'Darasuram Temple'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/madurai-temple.jpg' },
    { name: 'Karaikudi', slug: 'karaikudi', desc: 'The cultural capital of the Chettinad region, famous for the magnificent Chettiar mansions — sprawling palatial homes built by the wealthy Nattukottai Chettiars with stunning Athangudi handmade tiles, Burmese teak pillars, Italian marble, and Belgian glass. The Chettinad cuisine is considered one of India\'s finest culinary traditions — spicy, aromatic, and unforgettable. The Kanadukathan Palace, antique markets selling Chettinad artifacts, and beautiful temples make Karaikudi a heritage lover\'s dream.', category: 'Heritage Town', highlights: ['Chettinad Mansions', 'Chettinad Cuisine', 'Athangudi Tiles', 'Kanadukathan Palace', 'Chettinad Palace', 'Antique Markets'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏛️', img: '/madurai-temple.jpg' },
    { name: 'Tiruvannamalai', slug: 'tiruvannamalai', desc: 'Home to the sacred Arunachaleswarar Temple — one of the largest temple complexes in India, dedicated to Lord Shiva who manifested here as a column of fire (Agni Lingam). The holy Annamalai Hill (2668 feet) is considered a manifestation of Lord Shiva himself, and the full moon Girivalam (14-km circumambulation around the hill) draws hundreds of thousands of pilgrims every month. The great sage Ramana Maharshi lived and taught at the peaceful Ramana Ashram, attracting spiritual seekers from around the world.', category: 'Pilgrimage', highlights: ['Arunachaleswarar Temple', 'Annamalai Hill', 'Ramana Ashram', 'Girivalam', 'Skandashramam', 'Seshadri Swamigal Ashram'], bestTime: 'Nov - Feb', duration: '2 Days', emoji: '🛕', img: '/madurai-temple.jpg' },
    { name: 'Sivakasi', slug: 'sivakasi', desc: 'The fireworks capital of India and a major printing and matchbox manufacturing hub, producing 90% of India\'s fireworks, 60% of safety matches, and a significant portion of printed materials. Known as Little Japan for its industrial prowess and work ethic, this small town in Virudhunagar district has an outsized impact on celebrations across India. The nearby Ayyanar Falls in the scenic Western Ghats and the ancient Srivilliputhur Andal Temple (one of the 108 Divya Desams) offer natural and spiritual respite.', category: 'Industrial Town', highlights: ['Fireworks Industry', 'Printing Industry', 'Ayyanar Falls', 'Srivilliputhur Temple', 'Matchbox Factories', 'Grizzled Squirrel Sanctuary'], bestTime: 'Oct - Mar', duration: '1 Day', emoji: '🎆', img: '/states/tamilnadu-cover.jpg' },
    { name: 'Tuticorin (Thoothukudi)', slug: 'tuticorin', desc: 'Major port city and pearl fishing center on the Gulf of Mannar, known as the Pearl City of India for its historic pearl diving tradition. The beautiful Roche Park, the historic Our Lady of Snows Basilica — one of South India\'s largest churches, the scenic Beach Road, and a thriving salt production industry make Tuticorin unique. The city is also a gateway to the beautiful Gulf of Mannar Marine National Park with its rich coral reefs and marine biodiversity.', category: 'Coastal City', highlights: ['Pearl Fishing', 'Our Lady of Snows Basilica', 'Roche Park', 'Beach Road', 'Gulf of Mannar Marine NP', 'Harbour View'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🏖️', img: '/chennai-marina.jpg' },
    { name: 'Nagercoil', slug: 'nagercoil', desc: 'A beautiful town near Kanyakumari known for its pleasant climate, lush green paddy fields, ancient temples, and the famous Nagaraja Temple dedicated to the serpent god — unique in Tamil Nadu. Gateway to the hill stations of Kanyakumari district including the beautiful Thirparappu Falls. The nearby Padmanabhapuram Palace — a magnificent 16th-century wooden palace of the Travancore kings — is considered the finest example of traditional Kerala architecture in existence.', category: 'Temple Town', highlights: ['Nagaraja Temple', 'Suchindram Temple', 'Padmanabhapuram Palace', 'Vattakottai Fort', 'Thirparappu Falls', 'Udayagiri Fort'], bestTime: 'Oct - Mar', duration: '1-2 Days', emoji: '🛕', img: '/kanyakumari.jpg' },
  ],
};

